#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int t, a, b, c, d;
int k;
int to;
int p[10000005];
int v[10000005];
void prim () {
	memset (v, 0, sizeof (v));
	for (int i = 2; i <= 1e7; i++) {
		if (!v[i]) {
			p[++k] = v[i] = i;
		}
		for (int j = 1; j <= k; j++) {
			if (p[j] > v[i] || p[j] > 1e7 / i) {
				break;
			}
			v[i * p[j]] = p[j];
		}
	}
	return;
}
bool check () {
	int aa, bb, cc, dd, na, nb, nc, nd;
	to = (d > b ? d : b);
	for(int i = 1; p[i] <= to && i <= k; i++) {
		aa = a - 1;
		bb = b;
		cc = c - 1;
		dd = d;
		na = nb = nc = nd = 0;
		while (aa) {
			aa /= p[i];
			na += aa;
		}
		while (bb) {
			bb /= p[i];
			nb += bb;
		}
		while (cc) {
			cc /= p[i];
			nc += cc;
		}
		while (dd) {
			dd /= p[i];
			nd += dd; 
		}
		if (nb - na > nd - nc) {
			return false;
		}
	}
	return true;
}
signed main() {
	cin >> t;
	prim();
	while (t--) {
		cin >> a >> b >> c >> d;
		check() == 1 ? cout << "DA\n" : cout << "NE\n";
	}
	return 0;
}
